import functools


class ValidationError(Exception):
    """Raised when validation fails."""
    def __init__(self, field, message, value=None):
        self.field = field
        self.message = message
        self.value = value
        super().__init__(f"{field}: {message}")


def validate(func=None, *, strict=False):
    """Decorator that validates function inputs against type hints.

    When strict=True, raises ValidationError on first failure.
    When strict=False, collects all errors and raises at end.
    """
    def decorator(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            errors = []
            hints = fn.__annotations__

            # Validate keyword arguments against type hints
            for name, expected_type in hints.items():
                if name == 'return':
                    continue
                if name in kwargs:
                    val = kwargs[name]
                    if not isinstance(val, expected_type):
                        err = ValidationError(name, f"expected {expected_type.__name__}, got {type(val).__name__}", val)
                        if strict:
                            raise err
                        errors.append(err)

            if errors:
                raise ValidationError("multiple", f"{len(errors)} validation errors", errors)

            return fn(*args, **kwargs)
        wrapper._is_validated = True
        wrapper._strict = strict
        return wrapper

    if func is not None:
        return decorator(func)
    return decorator

