from .core import ValidationError


def required(value, field_name="field"):
    """Check that a value is not None or empty."""
    if value is None or (isinstance(value, str) and not value.strip()):
        raise ValidationError(field_name, "is required", value)
    return value


def min_length(value, length, field_name="field"):
    """Check minimum length."""
    if len(value) < length:
        raise ValidationError(field_name, f"must be at least {length} characters", value)
    return value


def max_length(value, length, field_name="field"):
    """Check maximum length."""
    if len(value) > length:
        raise ValidationError(field_name, f"must be at most {length} characters", value)
    return value


def matches_pattern(value, pattern, field_name="field"):
    """Check value matches regex pattern."""
    import re
    if not re.match(pattern, value):
        raise ValidationError(field_name, f"must match pattern {pattern}", value)
    return value

