from .core import ValidationError


def all_of(*validators):
    """All validators must pass."""
    def check(value, field_name="field"):
        errors = []
        for v in validators:
            try:
                v(value, field_name=field_name)
            except ValidationError as e:
                errors.append(e)
        if errors:
            raise ValidationError(field_name, f"{len(errors)} checks failed", errors)
        return value
    return check


def any_of(*validators):
    """At least one validator must pass."""
    def check(value, field_name="field"):
        errors = []
        for v in validators:
            try:
                v(value, field_name=field_name)
                return value
            except ValidationError as e:
                errors.append(e)
        raise ValidationError(field_name, "no validators passed", errors)
    return check

