from .core import ValidationError


class ValidationReport:
    """Collects validation results."""

    def __init__(self):
        self.errors = []
        self.warnings = []

    def add_error(self, error):
        """Add a ValidationError to the report."""
        if isinstance(error, ValidationError):
            self.errors.append(error)
        else:
            self.errors.append(ValidationError("unknown", str(error)))

    def add_warning(self, field, message):
        """Add a warning (non-fatal)."""
        self.warnings.append({"field": field, "message": message})

    def is_valid(self):
        """True if no errors."""
        return len(self.errors) == 0

    def summary(self):
        """Return summary string."""
        return f"{len(self.errors)} errors, {len(self.warnings)} warnings"

    def raise_if_invalid(self):
        """Raise ValidationError if any errors exist."""
        if not self.is_valid():
            raise ValidationError("report", self.summary(), self.errors)

