from .core import validate, ValidationError
from .rules import required, min_length, max_length


class Schema:
    """Declarative validation schema."""

    def __init__(self, fields):
        self.fields = fields  # dict of field_name -> list of rule funcs

    def validate_data(self, data):
        """Validate a dict against the schema.

        Returns list of ValidationError instances.
        """
        errors = []
        for field_name, rules in self.fields.items():
            value = data.get(field_name)
            for rule in rules:
                try:
                    rule(value, field_name=field_name)
                except ValidationError as e:
                    errors.append(e)
        return errors

    def is_valid(self, data):
        """Check if data is valid."""
        return len(self.validate_data(data)) == 0

    def validate_or_raise(self, data):
        """Validate and raise on first error."""
        errors = self.validate_data(data)
        if errors:
            raise errors[0]

