from .core import ValidationError
from .schema import Schema


class ValidationMiddleware:
    """Middleware that validates request data against a schema."""

    def __init__(self, schema):
        self.schema = schema

    def process(self, request):
        """Validate request data, return errors or None."""
        try:
            errors = self.schema.validate_data(request.get("data", {}))
            if errors:
                return {
                    "valid": False,
                    "errors": [{"field": e.field, "message": e.message} for e in errors]
                }
            return {"valid": True, "errors": []}
        except ValidationError as e:
            return {"valid": False, "errors": [{"field": e.field, "message": e.message}]}

