from .core import ValidationError, validate


def safe_validate(func, *args, **kwargs):
    """Run a validated function and return (result, error) tuple."""
    try:
        result = func(*args, **kwargs)
        return result, None
    except ValidationError as e:
        return None, e


def is_validated(func):
    """Check if a function has the @validate decorator."""
    return getattr(func, '_is_validated', False)


def get_validation_mode(func):
    """Get the validation mode (strict/lenient) of a decorated function."""
    if not is_validated(func):
        raise ValueError(f"{func.__name__} is not decorated with @validate")
    return "strict" if getattr(func, '_strict', False) else "lenient"

