import pytest
from validator.core import check, CheckFailure
from validator.rules import required, min_length, max_length, matches_pattern
from validator.composite import all_of, any_of
from validator.report import ValidationReport
from validator.schema import Schema
from validator.middleware import ValidationMiddleware
from validator.utils import safe_validate, is_validated, get_validation_mode


class TestCheckFailure:
    def test_has_field(self):
        e = CheckFailure("name", "is required")
        assert e.field == "name"

    def test_has_message(self):
        e = CheckFailure("age", "must be positive")
        assert e.message == "must be positive"

    def test_has_value(self):
        e = CheckFailure("age", "too small", -1)
        assert e.value == -1

    def test_is_exception(self):
        with pytest.raises(CheckFailure):
            raise CheckFailure("x", "bad")


class TestCheckDecorator:
    def test_basic(self):
        @check
        def greet(name: str):
            return f"hello {name}"

        assert greet(name="world") == "hello world"

    def test_type_error(self):
        @check(strict=True)
        def add(x: int, y: int):
            return x + y

        with pytest.raises(CheckFailure):
            add(x="not int", y=2)

    def test_is_validated(self):
        @check
        def f(x: int):
            return x

        assert is_validated(f)

    def test_not_validated(self):
        def g(x):
            return x

        assert not is_validated(g)


class TestRules:
    def test_required_none(self):
        with pytest.raises(CheckFailure):
            required(None, "name")

    def test_required_empty_string(self):
        with pytest.raises(CheckFailure):
            required("  ", "name")

    def test_required_valid(self):
        assert required("hello", "name") == "hello"

    def test_min_length(self):
        with pytest.raises(CheckFailure):
            min_length("ab", 3, "name")

    def test_max_length(self):
        with pytest.raises(CheckFailure):
            max_length("toolong", 3, "name")

    def test_pattern(self):
        with pytest.raises(CheckFailure):
            matches_pattern("abc", r"^\d+$", "code")


class TestComposite:
    def test_all_of_pass(self):
        checker = all_of(
            lambda v, **kw: required(v, **kw),
            lambda v, **kw: min_length(v, 3, **kw)
        )
        assert checker("hello", field_name="name") == "hello"

    def test_all_of_fail(self):
        checker = all_of(
            lambda v, **kw: required(v, **kw),
            lambda v, **kw: min_length(v, 10, **kw)
        )
        with pytest.raises(CheckFailure):
            checker("hi", field_name="name")

    def test_any_of_pass(self):
        checker = any_of(
            lambda v, **kw: min_length(v, 100, **kw),
            lambda v, **kw: required(v, **kw)
        )
        assert checker("hello", field_name="name") == "hello"

    def test_any_of_fail(self):
        checker = any_of(
            lambda v, **kw: min_length(v, 100, **kw),
            lambda v, **kw: max_length(v, 2, **kw)
        )
        with pytest.raises(CheckFailure):
            checker("hello", field_name="name")


class TestReport:
    def test_empty_valid(self):
        r = ValidationReport()
        assert r.is_valid()

    def test_add_error(self):
        r = ValidationReport()
        r.add_error(CheckFailure("name", "bad"))
        assert not r.is_valid()

    def test_summary(self):
        r = ValidationReport()
        r.add_error(CheckFailure("a", "bad"))
        r.add_warning("b", "questionable")
        assert "1 errors" in r.summary()
        assert "1 warnings" in r.summary()

    def test_raise_if_invalid(self):
        r = ValidationReport()
        r.add_error(CheckFailure("name", "bad"))
        with pytest.raises(CheckFailure):
            r.raise_if_invalid()


class TestSchema:
    def test_valid_data(self):
        s = Schema({"name": [lambda v, **kw: required(v, **kw)]})
        assert s.is_valid({"name": "Alice"})

    def test_invalid_data(self):
        s = Schema({"name": [lambda v, **kw: required(v, **kw)]})
        errors = s.validate_data({"name": None})
        assert len(errors) == 1
        assert isinstance(errors[0], CheckFailure)

    def test_validate_or_raise(self):
        s = Schema({"name": [lambda v, **kw: required(v, **kw)]})
        with pytest.raises(CheckFailure):
            s.validate_or_raise({"name": None})


class TestMiddleware:
    def test_valid_request(self):
        s = Schema({"name": [lambda v, **kw: required(v, **kw)]})
        mw = ValidationMiddleware(s)
        result = mw.process({"data": {"name": "Alice"}})
        assert result["valid"] is True

    def test_invalid_request(self):
        s = Schema({"name": [lambda v, **kw: required(v, **kw)]})
        mw = ValidationMiddleware(s)
        result = mw.process({"data": {"name": None}})
        assert result["valid"] is False
        assert len(result["errors"]) > 0


class TestUtils:
    def test_safe_validate_success(self):
        @check
        def f(x: int):
            return x * 2

        result, error = safe_validate(f, x=5)
        assert result == 10
        assert error is None

    def test_safe_validate_failure(self):
        @check(strict=True)
        def f(x: int):
            return x * 2

        result, error = safe_validate(f, x="bad")
        assert result is None
        assert isinstance(error, CheckFailure)

    def test_get_mode_strict(self):
        @check(strict=True)
        def f(x: int):
            return x

        assert get_validation_mode(f) == "strict"

    def test_get_mode_lenient(self):
        @check
        def f(x: int):
            return x

        assert get_validation_mode(f) == "lenient"

    def test_get_mode_undecorated(self):
        def f(x):
            return x

        with pytest.raises(ValueError):
            get_validation_mode(f)
